import network
import socket
import time
from microcoapy import coap

WIFI_SSID = 'YOUR_WIFI_SSID'
WIFI_PASSWORD = 'YOUR_WIFI_PASSWORD'

_current_temperature = 25.0
_light_state = False

def get_temperature_handler(request, client_address):
    global _current_temperature
    _current_temperature += 0.1
    if _current_temperature > 30.0:
        _current_temperature = 25.0
    
    payload = f"{_current_temperature:.1f}C"
    return coap.COAP_CODE_CONTENT, payload.encode('utf-8')

def light_handler(request, client_address):
    global _light_state
    
    if request.code == coap.COAP_CODE_GET:
        payload = "ON" if _light_state else "OFF"
        return coap.COAP_CODE_CONTENT, payload.encode('utf-8')
    
    elif request.code == coap.COAP_CODE_PUT:
        new_state_str = request.payload.decode('utf-8').strip().upper()
        
        if new_state_str == "ON":
            _light_state = True
            return coap.COAP_CODE_CHANGED, b''
        elif new_state_str == "OFF":
            _light_state = False
            return coap.COAP_CODE_CHANGED, b''
        else:
            return coap.COAP_CODE_BAD_REQUEST, b'Invalid state. Use "ON" or "OFF".'
            
    else:
        return coap.COAP_CODE_METHOD_NOT_ALLOWED, b''

def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        timeout = 10
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
        if not wlan.isconnected():
            raise Exception("Could not connect to Wi-Fi!")
    return wlan

def main():
    try:
        wlan = connect_wifi(WIFI_SSID, WIFI_PASSWORD)
    except Exception as e:
        return

    server = coap.Coap()

    server.add_resource('sensors/temp', get_temperature_handler)
    server.add_resource('actuators/light', light_handler)

    try:
        server.listen()
    except KeyboardInterrupt:
        pass
    except Exception as e:
        pass
    finally:
        server.close()
        wlan.disconnect()
        wlan.active(False)

if __name__ == '__main__':
    main()